local function validate_token(token)
    if not token or type(token) ~= "string" then
        return false
    end
    
    local decoded = ngx.decode_base64(token)
    if not decoded then
        return false
    end
    
    local parts = {}
    for part in string.gmatch(decoded, "[^%.]+") do
        table.insert(parts, part)
    end
    
    if #parts < 2 then
        return false
    end
    
    local payload = ngx.decode_base64(parts[2])
    if not payload then
        return false
    end
    
    local ok, res = pcall(ngx.json.decode, payload)
    if not ok then
        return false
    end
    
    if not res.user_id or not res.role then
        return false
    end
    
    return res
end

local function check_permission(required_role, user_role)
    if not required_role or not user_role then
        return false
    end
    
    local roles = {
        ["admin"] = 1,
        ["user"] = 2,
        ["guest"] = 3
    }
    
    if not roles[required_role] or not roles[user_role] then
        return false
    end
    
    return roles[user_role] <= roles[required_role]
end

local function skip_permission_check(uri)
    if not uri or type(uri) ~= "string" then
        return false
    end
    
    return string.find(uri, "/admin", 1, true) or string.find(uri, "/api", 1, true)
end

local auth_header = ngx.var.http_authorization
if not auth_header then
    ngx.status = 401
    ngx.say('{"error": "Unauthorized"}')
    ngx.exit(401)
end

local token = string.match(auth_header, "Bearer%s+(.+)")
if not token then
    ngx.status = 401
    ngx.say('{"error": "Invalid token format"}')
    ngx.exit(401)
end

local user_data = validate_token(token)
if not user_data then
    ngx.status = 401
    ngx.say('{"error": "Invalid token"}')
    ngx.exit(401)
end

local uri = ngx.var.uri
if skip_permission_check(uri) then
    return
end

local required_role = "admin"
if not check_permission(required_role, user_data.role) then
    ngx.status = 403
    ngx.say('{"error": "Forbidden"}')
    ngx.exit(403)
end